// src/components/payment/Payment.jsx
import { useState, useEffect } from "react";
import './Payment.css';

const AmountForm = ({ amount = 0, transportData }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [paymentData, setPaymentData] = useState(null);

  // Auto-submit when amount is provided
  useEffect(() => {
    if (amount && amount >= 10 && amount <= 50000) {
      handleSubmit(amount);
    }
  }, [amount]);

  const handleSubmit = async (submitAmount) => {
    if (!submitAmount || submitAmount < 10 || submitAmount > 50000) {
      setError("Amount must be between ₹10 and ₹50,000");
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      if (!token) {
        setError("Authentication required. Please login.");
        setIsLoading(false);
        return;
      }

      console.log("Sending payment request with amount:", submitAmount);

      const response = await fetch(
        `https://chagans.com/payment/addMoneyTen`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json"
          },
          body: JSON.stringify({
            amount: submitAmount, 
            transportData: {
              ...transportData,
              trackingId: `TRK${Math.floor(100000 + Math.random() * 900000)}`,
            },
            mobile: "7983920962",
            apiType: "API",
          }),
        }
      );

      console.log("Response status:", response.status);
      
      if (!response.ok) {
        const errorText = await response.text();
        console.error("Error response:", errorText);
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      console.log("Payment response data:", data);
      
      if (data.success) {
        setPaymentData(data.data);
        setError(""); // Clear any errors
      } else {
        setError(data.message || "Payment failed. Please try again.");
      }
    } catch (err) {
      console.error('Full payment error:', err);
      setError("Network error. Please check your connection.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="amount-form-container">
      {/* Loading State */}
      {isLoading && (
        <div className="loading-indicator">
          <div className="spinner"></div>
          <p>Initializing payment...</p>
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="error-message">
          <svg className="error-icon" viewBox="0 0 24 24" width="20" height="20">
            <circle cx="12" cy="12" r="10" fill="#fee"/>
            <path d="M12 8v4M12 16h.01" stroke="#dc2626" strokeWidth="2" strokeLinecap="round"/>
          </svg>
          <p>{error}</p>
        </div>
      )}

      {/* Payment Data Display with QR Code */}
      {paymentData && (
        <div className="payment-data">
          <h3 style={{textAlign: 'center', marginBottom: '20px', color: '#333'}}>
            <span style={{fontSize: '24px'}}>📱</span> Scan QR Code to Pay
          </h3>
          
          {/* Amount Display */}
          <div style={{textAlign: 'center', marginBottom: '25px'}}>
            <div style={{fontSize: '14px', color: '#666', marginBottom: '5px'}}>Total Amount</div>
            <div style={{fontSize: '32px', fontWeight: 'bold', color: '#16a34a'}}>
              ₹{parseInt(paymentData.AMOUNT)/100}
            </div>
          </div>

          {/* QR Code using multiple fallback methods */}
          <div style={{textAlign: 'center', marginBottom: '25px'}}>
            {/* Method 1: Google Charts API */}
            <img 
              src={`https://chart.googleapis.com/chart?chs=250x250&cht=qr&chl=UPI://pay?pa=${paymentData.PAY_ID}@paytm&pn=FuelDrop&am=${parseInt(paymentData.AMOUNT)/100}&cu=INR`}
              alt="Payment QR Code"
              style={{width: '220px', height: '220px', border: '2px solid #ddd', borderRadius: '12px', padding: '5px'}}
              onError={(e) => {
                // Method 2: If Google Charts fails, use QR Server
                e.target.src = `https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=UPI://pay?pa=${paymentData.PAY_ID}@paytm&pn=FuelDrop&am=${parseInt(paymentData.AMOUNT)/100}&cu=INR`;
              }}
            />
          </div>

          {/* UPI String Alternative */}
          <div style={{textAlign: 'center', marginBottom: '20px'}}>
            <p style={{fontSize: '12px', color: '#666', marginBottom: '5px'}}>Or pay using UPI ID:</p>
            <div style={{
              background: '#f0f0f0',
              padding: '10px',
              borderRadius: '8px',
              fontFamily: 'monospace',
 fontSize: '14px',
              border: '1px dashed #999',
              display: 'inline-block'
            }}>
              {paymentData.PAY_ID}@paytm
            </div>
          </div>

          {/* Payment Details */}
          <div className="payment-details" style={{
            background: '#f8f9fa',
            padding: '15px',
            borderRadius: '10px',
            marginBottom: '20px',
            border: '1px solid #e9ecef'
          }}>
            <h4 style={{margin: '0 0 12px 0', fontSize: '16px', color: '#495057'}}>📋 Payment Details</h4>
            <p style={{margin: '8px 0', fontSize: '14px'}}>
              <strong>Order ID:</strong> <span style={{color: '#2c3e50'}}>{paymentData.ORDER_ID}</span>
            </p>
            <p style={{margin: '8px 0', fontSize: '14px'}}>
              <strong>Payment ID:</strong> <span style={{color: '#2c3e50'}}>{paymentData.PAY_ID}</span>
            </p>
            <p style={{margin: '8px 0', fontSize: '14px'}}>
              <strong>Name:</strong> <span style={{color: '#2c3e50'}}>{paymentData.CUST_NAME}</span>
            </p>
          </div>

          {/* Instructions */}
          <div style={{
            background: '#e3f2fd',
            padding: '18px',
            borderRadius: '10px',
            border: '1px solid #bbdefb'
          }}>
            <p style={{margin: '0 0 12px 0', fontWeight: 'bold', color: '#1976d2'}}>
              📱 How to Pay:
            </p>
            <ol style={{margin: '0', paddingLeft: '20px', color: '#2c3e50'}}>
              <li style={{marginBottom: '8px'}}>Open any UPI app (Google Pay, PhonePe, PayTM)</li>
              <li style={{marginBottom: '8px'}}>Tap on "Scan QR Code" or "Pay by QR"</li>
              <li style={{marginBottom: '8px'}}>Scan this QR code</li>
              <li style={{marginBottom: '8px'}}>Verify amount: <strong>₹{parseInt(paymentData.AMOUNT)/100}</strong></li>
              <li>Complete the payment</li>
            </ol>
          </div>

          {/* Note */}
          <p style={{textAlign: 'center', fontSize: '12px', color: '#999', marginTop: '15px'}}>
            ⏱️ QR code expires in 15 minutes
          </p>
        </div>
      )}
    </div>
  );
};

export default AmountForm;
